// Extract and normalize call data from VAPI end-of-call-report
const body = $input.first().json.body;
const message = body.message || {};
const call = message.call || {};
const artifact = message.artifact || {};
const analysis = message.analysis || {};

// Calculate duration in seconds
let durationSeconds = 0;
if (call.startedAt && call.endedAt) {
  const start = new Date(call.startedAt).getTime();
  const end = new Date(call.endedAt).getTime();
  durationSeconds = Math.round((end - start) / 1000);
}

// Determine call outcome
const endedReason = message.endedReason || call.endedReason || '';
const transcript = artifact.transcript || '';

let outcome = 'Answered';
const lowerTranscript = transcript.toLowerCase();

if (lowerTranscript.includes('escalat') || lowerTranscript.includes('specialist') || lowerTranscript.includes('support team will contact')) {
  outcome = 'Escalated';
} else if (
  endedReason === 'silence-timed-out' ||
  endedReason === 'no-answer' ||
  endedReason === 'customer-did-not-answer'
) {
  outcome = 'Dropped';
} else if (
  lowerTranscript.includes("i'm not able to help with that") ||
  lowerTranscript.includes('outside the scope') ||
  lowerTranscript.includes('cannot confidently')
) {
  outcome = 'Declined';
}

return [{
  json: {
    callId: call.id || '',
    timestamp: call.startedAt || new Date().toISOString(),
    durationSeconds: durationSeconds,
    transcript: transcript,
    outcome: outcome,
    endedReason: endedReason,
    summary: analysis.summary || '',
    agentVersion: 'v1.0'
  }
}];
